const express = require('express');
const mongoose = require('mongoose');
const app = express();

app.use(express.json());

const connectDB = async () => {
  try {
    await mongoose.connect(process.env.MONGODB_URI || 'mongodb://localhost:27017/queryservice', {
      useNewUrlParser: true,
      useUnifiedTopology: true,
    });
    console.log('MongoDB connected');
  } catch (error) {
    console.error('MongoDB connection error:', error);
    process.exit(1);
  }
};

connectDB();

const validateQuery = (query) => {
  const allowedOperators = ['$eq', '$ne', '$gt', '$gte', '$lt', '$lte', '$in', '$nin', '$regex', '$options', '$or', '$and', '$not', '$exists', '$type', '$text', '$search', '$language', '$caseSensitive', '$diacriticSensitive'];
  
  const validateOperator = (obj) => {
    if (typeof obj === 'object' && obj !== null) {
      for (const [key, value] of Object.entries(obj)) {
        if (key.startsWith('$') && !allowedOperators.includes(key)) {
          throw new Error(`Unauthorized operator: ${key}`);
        }
        if (typeof value === 'object' && value !== null) {
          validateOperator(value);
        }
      }
    }
  };

  validateOperator(query);
};

const sanitizeInput = (input) => {
  if (typeof input === 'string') {
    return input.replace(/[\x00-\x1F\x7F-\x9F]/g, '');
  }
  if (typeof input === 'object' && input !== null) {
    const sanitized = {};
    for (const [key, value] of Object.entries(input)) {
      sanitized[key] = sanitizeInput(value);
    }
    return sanitized;
  }
  return input;
};

app.post('/query', async (req, res) => {
  try {
    const { collection, query, options = {} } = req.body;
    
    if (!collection) {
      return res.status(400).json({ error: 'Collection name is required' });
    }
    
    if (!query) {
      return res.status(400).json({ error: 'Query is required' });
    }
    
    const sanitizedQuery = sanitizeInput(query);
    validateQuery(sanitizedQuery);
    
    const db = mongoose.connection;
    const collectionRef = db.collection(collection);
    
    const result = await collectionRef.find(sanitizedQuery, options);
    
    res.json({
      success: true,
      data: result,
      count: result.length
    });
  } catch (error) {
    console.error('Query error:', error);
    if (error.name === 'MongoError' || error.name === 'ValidationError') {
      return res.status(400).json({ error: 'Invalid query parameters' });
    }
    res.status(500).json({ error: 'Internal server error' });
  }
});

app.get('/health', (req, res) => {
  res.json({ status: 'OK', timestamp: new Date().toISOString() });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;